8143 /// Match clamp pattern for float types without care about NaNs or signed zeros.
8144 /// Given non-min/max outer cmp/select from the clamp pattern this
8145 /// function recognizes if it can be substitued by a "canonical" min/max
8146 /// pattern.
8147 static SelectPatternResult matchFastFloatClamp(CmpInst::Predicate Pred,
8148                                                Value *CmpLHS, Value *CmpRHS,
8149                                                Value *TrueVal, Value *FalseVal,
8150                                                Value *&LHS, Value *&RHS) {
8151   // Try to match
8152   //   X < C1 ? C1 : Min(X, C2) --> Max(C1, Min(X, C2))
8153   //   X > C1 ? C1 : Max(X, C2) --> Min(C1, Max(X, C2))
8154   // and return description of the outer Max/Min.
8155 
8156   // First, check if select has inverse order:
8157   if (CmpRHS == FalseVal) {
8158     std::swap(TrueVal, FalseVal);
8159     Pred = CmpInst::getInversePredicate(Pred);
8160   }
8161 
8162   // Assume success now. If there's no match, callers should not use these anyway.
8163   LHS = TrueVal;
8164   RHS = FalseVal;
8165 
8166   const APFloat *FC1;
8167   if (CmpRHS != TrueVal || !match(CmpRHS, m_APFloat(FC1)) || !FC1->isFinite())
8168     return {SPF_UNKNOWN, SPNB_NA, false};
8169 
8170   const APFloat *FC2;
8171   switch (Pred) {
8172   case CmpInst::FCMP_OLT:
8173   case CmpInst::FCMP_OLE:
8174   case CmpInst::FCMP_ULT:
8175   case CmpInst::FCMP_ULE:
8176     if (match(FalseVal, m_OrdOrUnordFMin(m_Specific(CmpLHS), m_APFloat(FC2))) &&
8177         *FC1 < *FC2)
8178       return {SPF_FMAXNUM, SPNB_RETURNS_ANY, false};
8179     break;
8180   case CmpInst::FCMP_OGT:
8181   case CmpInst::FCMP_OGE:
8182   case CmpInst::FCMP_UGT:
8183   case CmpInst::FCMP_UGE:
8184     if (match(FalseVal, m_OrdOrUnordFMax(m_Specific(CmpLHS), m_APFloat(FC2))) &&
8185         *FC1 > *FC2)
8186       return {SPF_FMINNUM, SPNB_RETURNS_ANY, false};
8187     break;
8188   default:
8189     break;
8190   }
8191 
8192   return {SPF_UNKNOWN, SPNB_NA, false};
8193 }
