8210         C1->slt(*C2) && Pred == CmpInst::ICMP_SLT)
8211       return {SPF_SMAX, SPNB_NA, false};
8212 
8213     // (X >s C1) ? C1 : SMAX(X, C2) ==> SMIN(SMAX(X, C2), C1)
8214     if (match(FalseVal, m_SMax(m_Specific(CmpLHS), m_APInt(C2))) &&
8215         C1->sgt(*C2) && Pred == CmpInst::ICMP_SGT)
8216       return {SPF_SMIN, SPNB_NA, false};
8217 
8218     // (X <u C1) ? C1 : UMIN(X, C2) ==> UMAX(UMIN(X, C2), C1)
8219     if (match(FalseVal, m_UMin(m_Specific(CmpLHS), m_APInt(C2))) &&
8220         C1->ult(*C2) && Pred == CmpInst::ICMP_ULT)
8221       return {SPF_UMAX, SPNB_NA, false};
8222 
8223     // (X >u C1) ? C1 : UMAX(X, C2) ==> UMIN(UMAX(X, C2), C1)
